const body = $json.body || $json;
if (!body.action) throw new Error('action zorunlu');

const action = body.action.trim().toLowerCase();
const payload = body.payload || {};
const session_key = body.session_key || '';

// Oturum gerektiren action'lar
const SESSION_REQUIRED = ['check_quota', 'upload_receipt', 'get_reports'];
if (SESSION_REQUIRED.includes(action) && !session_key) {
  throw new Error('Bu islem icin session_key zorunlu');
}

return [{ json: { action, payload, session_key, _step: 1 } }];

// ================================================================
//  DYNAMIC SQL ENGINE - Tum action + step kombinasyonlari burada
// ================================================================
const { action, payload, session_key, _step, _prev } = $json;

const ACTIONS = {

  // ==================== LOGIN ====================
  login: {
    1: {
      validate: () => {
        if (!payload.email || !payload.password)
          throw new Error('email ve password zorunlu');
      },
      sql: `SELECT u.id, u.company_id, u.role, u.is_super_admin
            FROM users u
            WHERE lower(u.email) = lower($1)
              AND u.password_hash = crypt($2, u.password_hash)
              AND u.status = 'true'
            LIMIT 1`,
      params: () => [payload.email, payload.password]
    },
    2: {
      sql: `INSERT INTO user_sessions (user_id, session_key, expires_at, user_agent)
            VALUES ($1, encode(gen_random_bytes(32), 'hex'), now() + interval '15 days', $2)
            RETURNING session_key, expires_at`,
      params: () => [_prev.id, payload.user_agent || 'web']
    }
  },

  // ==================== REGISTER ====================
  register: {
    1: {
      validate: () => {
        if (!payload.company_name || !payload.email || !payload.password)
          throw new Error('company_name, email ve password zorunlu');
      },
      sql: `SELECT create_trial_company_and_admin($1, $2, crypt($3, gen_salt('bf')), $4) AS user_id`,
      params: () => [payload.company_name, payload.email, payload.password, payload.telegram_id || null]
    }
  },

  // ==================== CHECK QUOTA ====================
  check_quota: {
    1: {
      sql: `SELECT c.id AS company_id, check_company_quota(c.id) AS allow
            FROM user_sessions s
            JOIN users u ON u.id = s.user_id
            JOIN companies c ON c.id = u.company_id
            WHERE s.session_key = $1
              AND s.revoked_at IS NULL AND s.expires_at > now()
            LIMIT 1`,
      params: () => [session_key]
    }
  },

  // ==================== GET REPORTS ====================
  get_reports: {
    1: {
      sql: `SELECT u.id AS user_id, u.role, u.is_super_admin, u.company_id,
                   c.company_name, c.plan_type, c.monthly_limit, c.extra_credits,
                   c.used_this_month, c.status
            FROM user_sessions s
            JOIN users u ON u.id = s.user_id
            LEFT JOIN companies c ON c.id = u.company_id
            WHERE s.session_key = $1
              AND s.revoked_at IS NULL AND s.expires_at > now()
            LIMIT 1`,
      params: () => [session_key]
    }
  },

  // ==================== FORGOT PASSWORD ====================
  forgot_password: {
    1: {
      validate: () => {
        if (!payload.email) throw new Error('email zorunlu');
      },
      sql: `SELECT id, email, coalesce(full_name, split_part(email, '@', 1)) AS full_name
            FROM users
            WHERE lower(email) = lower($1) AND status = 'true'
            LIMIT 1`,
      params: () => [payload.email]
    },
    2: {
      sql: `UPDATE users
            SET password_hash = crypt($1, gen_salt('bf')), updated_at = now()
            WHERE id = $2 RETURNING id`,
      params: () => [_prev.temp_password, _prev.user_id]
    }
  }
};

// Action kontrolu
const actionDef = ACTIONS[action];
if (!actionDef) {
  return [{ json: { _done: true, _response: { ok: false, message: 'Bilinmeyen action: ' + action } } }];
}

const stepDef = actionDef[_step];
if (!stepDef) {
  return [{ json: { _done: true, _response: { ok: false, message: 'Gecersiz step: ' + action + '/' + _step } } }];
}

// Validasyon
if (stepDef.validate) stepDef.validate();

return [{ json: {
  action, payload, session_key, _step,
  _sql: stepDef.sql,
  _params: stepDef.params(),
  _prev: _prev || null
}}];

// ================================================================
//  STEP ROUTER - Sonucu degerlendir, sonraki step veya response uret
// ================================================================
const input = $('SQL Engine').first().json;
const { action, payload, session_key, _step } = input;
const rows = $input.all().map(i => i.json);
const row = rows[0] || {};

// ---------- LOGIN STEP 1 → step 2 ----------
if (action === 'login' && _step === 1) {
  if (!row.id) throw new Error('Gecersiz email veya sifre');
  return [{ json: {
    action, payload, session_key,
    _step: 2,
    _prev: row,
    _done: false
  }}];
}

// ---------- LOGIN STEP 2 → bitti ----------
if (action === 'login' && _step === 2) {
  return [{ json: {
    _done: true,
    _response: { ok: true, session_key: row.session_key, expires_at: row.expires_at }
  }}];
}

// ---------- REGISTER → bitti ----------
if (action === 'register') {
  return [{ json: {
    _done: true,
    _response: { ok: true, message: 'Kayit olusturuldu', user_id: row.user_id }
  }}];
}

// ---------- CHECK QUOTA → bitti ----------
if (action === 'check_quota') {
  return [{ json: {
    _done: true,
    _response: { ok: true, allow: row.allow || false, company_id: row.company_id || '' }
  }}];
}

// ---------- GET REPORTS → bitti ----------
if (action === 'get_reports') {
  if (!row.user_id) throw new Error('Gecersiz veya suresi dolmus oturum');
  return [{ json: {
    _done: true,
    _response: {
      ok: true,
      profile: { user_id: row.user_id, role: row.role, is_super_admin: row.is_super_admin },
      company: {
        company_id: row.company_id, name: row.name, plan_type: row.plan_type,
        monthly_limit: row.monthly_limit, extra_credits: row.extra_credits,
        used_this_month: row.used_this_month, status: row.status
      }
    }
  }}];
}

// ---------- FORGOT STEP 1 → kullanici var mi? ----------
if (action === 'forgot_password' && _step === 1) {
  const SAFE_MSG = 'Eger e-posta sistemde kayitliysa gecici sifre gonderildi.';

  if (!row.id) {
    // Kullanici yok - guvenlik icin ayni mesaj
    return [{ json: { _done: true, _response: { ok: true, message: SAFE_MSG } } }];
  }

  // Gecici sifre uret
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789';
  let tempPassword = '';
  for (let i = 0; i < 8; i++) {
    tempPassword += chars.charAt(Math.floor(Math.random() * chars.length));
  }

  return [{ json: {
    action, payload, session_key,
    _step: 2,
    _prev: { ...row, temp_password: tempPassword },
    _done: false,
    _send_mail: true,
    _mail_data: { email: row.email, full_name: row.full_name, temp_password: tempPassword }
  }}];
}

// ---------- FORGOT STEP 2 → mail gonder ----------
if (action === 'forgot_password' && _step === 2) {
  const mailData = input._mail_data || (input._prev || {});
  return [{ json: {
    _done: 'send_mail',
    _mail_data: mailData,
    _response: { ok: true, message: 'Eger e-posta sistemde kayitliysa gecici sifre gonderildi.' }
  }}];
}

// Fallback
return [{ json: { _done: true, _response: { ok: true, data: row } } }];
